from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidUnitPriceError(ShoppingCartError):
    """Raised when a unit price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item cannot be found in the cart."""


class DiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Protocol for shopping cart discount strategies."""

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the discount amount for a given subtotal."""
        ...


@dataclass(frozen=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the percentage discount for a given subtotal."""
        return subtotal * (self.percentage / Decimal("100"))


@dataclass(frozen=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def calculate_discount(self, subtotal: Decimal) -> Decimal:
        """Calculate the flat discount for a given subtotal."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """A shopping cart for managing items, discounts, and totals."""

    def __init__(self) -> None:
        """Initialize an empty shopping cart."""
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal | int | float | str,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_product_name = self._validate_product_name(product_name)
        normalized_unit_price = self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)

        if existing_item is None:
            self._items[normalized_product_name] = CartItem(
                product_name=normalized_product_name,
                unit_price=normalized_unit_price,
                quantity=quantity,
            )
            return

        if existing_item.unit_price != normalized_unit_price:
            raise InvalidUnitPriceError(
                f"Existing item '{normalized_product_name}' has unit price "
                f"{existing_item.unit_price}, not {normalized_unit_price}."
            )

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=existing_item.quantity + quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = self._validate_product_name(product_name)
        self._get_item_or_raise(normalized_product_name)
        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = self._validate_product_name(product_name)
        self._validate_quantity(quantity)

        existing_item = self._get_item_or_raise(normalized_product_name)

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=quantity,
        )

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum(
            (item.total_price for item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal | int | float | str) -> None:
        """Apply a percentage discount to the cart."""
        normalized_percentage = self._to_decimal(percentage)

        if normalized_percentage < Decimal("0") or normalized_percentage > Decimal("100"):
            raise DiscountError("Percentage discount must be between 0 and 100.")

        self._discount = PercentageDiscount(normalized_percentage)

    def apply_flat_discount(self, amount: Decimal | int | float | str) -> None:
        """Apply a flat discount amount to the cart."""
        normalized_amount = self._to_decimal(amount)

        if normalized_amount < Decimal("0"):
            raise DiscountError("Flat discount amount cannot be negative.")

        self._discount = FlatDiscount(normalized_amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()
        discount_amount = self._calculate_discount_amount(subtotal)
        return subtotal - discount_amount

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all cart items."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _calculate_discount_amount(self, subtotal: Decimal) -> Decimal:
        if self._discount is None:
            return Decimal("0")

        return self._discount.calculate_discount(subtotal)

    def _get_item_or_raise(self, product_name: str) -> CartItem:
        try:
            return self._items[product_name]
        except KeyError as error:
            raise ItemNotFoundError(
                f"Item '{product_name}' was not found in the cart."
            ) from error

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_product_name = product_name.strip()

        if not normalized_product_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_product_name

    @classmethod
    def _validate_unit_price(
        cls,
        unit_price: Decimal | int | float | str,
    ) -> Decimal:
        normalized_unit_price = cls._to_decimal(unit_price)

        if normalized_unit_price < Decimal("0"):
            raise InvalidUnitPriceError("Unit price cannot be negative.")

        return normalized_unit_price

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

    @staticmethod
    def _to_decimal(value: Decimal | int | float | str) -> Decimal:
        try:
            return Decimal(str(value))
        except Exception as error:
            raise ShoppingCartError(f"Could not convert '{value}' to Decimal.") from error
